%%%%  Generate prediction equations (using toeplitz/hankel matrices) from %%%%  MFD model   A y(k+1) = B u(k)%%%%%%%%  yfut = H *Dufut + P*Dupast + Q*ypast%%%%%%%%  [H,P,Q] = mpc_predmat_toeplitz_control101(A,B,ny)%%%%%%%%  ny is the output horizon%%  %% Author: J.A. Rossiter  (email: J.A.Rossiter@shef.ac.uk)function [H,P,Q] = mpc_predmat_toeplitz_control101(A,B,ny);%%%%% Add integral to modelsizey = size(A,1);D = [eye(sizey),-eye(sizey)];AD = conv(A,D);nA = size(AD,2);nB = size(B,2);%%%% Find toeplitz and hankel matrices and hence predictions[Ca,Ha]=caha_control101(AD,sizey,ny);[Cb,Hb]=caha_control101(B,sizey,ny);Cai=inv(Ca);H=Cai*Cb; P=Cai*Hb; Q=-Cai*Ha;